import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { AuditoriaService } from '../../../core/services/auditoria.service';
import { AuthService } from '../../../core/services/auth.service';
import { EventoSistemaResponse, LoginAuditoriaResponse } from '../../../core/models/auditoria.model';

@Component({
  selector: 'app-auditoria',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './auditoria.component.html',
  styleUrls: ['./auditoria.component.css']
})
export class AuditoriaComponent implements OnInit {
  private auditoriaService = inject(AuditoriaService);
  private authService = inject(AuthService);
  private router = inject(Router);

  activeTab: 'login' | 'eventos' = 'login';
  isLoading = true;
  errorMsg = '';
  loginSearch = '';
  eventosSearch = '';
  loginSortOrder: 'desc' | 'asc' = 'desc';
  eventosSortOrder: 'desc' | 'asc' = 'desc';
  loginPage = 1;
  eventosPage = 1;
  readonly pageSize = 10;

  loginAuditoria: LoginAuditoriaResponse[] = [];
  eventosSistema: EventoSistemaResponse[] = [];

  ngOnInit(): void {
    this.authService.getProfile().subscribe({
      next: (profile) => {
        if (profile.rol !== 'ADMINISTRADOR') {
          this.router.navigate(['/dashboard']);
          return;
        }
        this.loadData();
      },
      error: () => {
        this.router.navigate(['/login']);
      }
    });
  }

  loadData(): void {
    this.isLoading = true;
    this.errorMsg = '';

    this.auditoriaService.getLoginAuditoria().subscribe({
      next: (data) => {
        this.loginAuditoria = data;
        this.auditoriaService.getEventosSistema().subscribe({
          next: (events) => {
            this.eventosSistema = events;
            this.isLoading = false;
          },
          error: (err) => this.handleError(err)
        });
      },
      error: (err) => this.handleError(err)
    });
  }

  setTab(tab: 'login' | 'eventos'): void {
    this.activeTab = tab;
  }

  get totalExitosos(): number {
    return this.loginAuditoria.filter(item => item.exitoso).length;
  }

  get totalFallidos(): number {
    return this.loginAuditoria.filter(item => !item.exitoso).length;
  }

  get usuariosBloqueados(): number {
    return this.loginAuditoria.filter(item => !!item.motivo?.toLowerCase().includes('bloque')).length;
  }

  get ultimosAccesos(): LoginAuditoriaResponse[] {
    return this.loginAuditoria.slice(0, 5);
  }

  get ultimosEventos(): EventoSistemaResponse[] {
    return this.eventosSistema.slice(0, 5);
  }

  private handleError(err: any): void {
    this.isLoading = false;
    this.errorMsg = err.error?.message || 'No se pudo cargar la auditoría.';
  }

  get filteredLoginAuditoria(): LoginAuditoriaResponse[] {
    const q = this.loginSearch.trim().toLowerCase();
    return this.loginAuditoria.filter(i =>
      !q || `${i.correo ?? ''} ${i.ip ?? ''} ${i.motivo ?? ''}`.toLowerCase().includes(q)
    ).sort((a, b) => {
      const d1 = new Date(a.fecha).getTime() || 0;
      const d2 = new Date(b.fecha).getTime() || 0;
      return this.loginSortOrder === 'asc' ? d1 - d2 : d2 - d1;
    });
  }

  get filteredEventosSistema(): EventoSistemaResponse[] {
    const q = this.eventosSearch.trim().toLowerCase();
    return this.eventosSistema.filter(i =>
      !q || `${i.modulo} ${i.accion} ${i.descripcion ?? ''} ${i.usuarioId ?? ''}`.toLowerCase().includes(q)
    ).sort((a, b) => {
      const d1 = new Date(a.fecha).getTime() || 0;
      const d2 = new Date(b.fecha).getTime() || 0;
      return this.eventosSortOrder === 'asc' ? d1 - d2 : d2 - d1;
    });
  }

  get pagedLoginAuditoria(): LoginAuditoriaResponse[] {
    const start = (this.loginPage - 1) * this.pageSize;
    return this.filteredLoginAuditoria.slice(start, start + this.pageSize);
  }

  get pagedEventosSistema(): EventoSistemaResponse[] {
    const start = (this.eventosPage - 1) * this.pageSize;
    return this.filteredEventosSistema.slice(start, start + this.pageSize);
  }

  get loginTotalPages(): number {
    return Math.max(1, Math.ceil(this.filteredLoginAuditoria.length / this.pageSize));
  }

  get eventosTotalPages(): number {
    return Math.max(1, Math.ceil(this.filteredEventosSistema.length / this.pageSize));
  }

  onLoginFilterChange(): void {
    this.loginPage = 1;
  }

  onEventosFilterChange(): void {
    this.eventosPage = 1;
  }
}
<div class="space-y-6 font-body text-slate-800 dark:text-slate-200 transition-colors duration-300">
  <div class="border border-slate-200 dark:border-slate-800 p-4 sm:p-6 bg-white dark:bg-slate-900 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
    <div class="flex flex-col gap-4">
      <div>
        <h1 class="text-2xl font-black uppercase text-slate-900 dark:text-slate-100">Auditoría de Seguridad</h1>
        <p class="text-xs text-slate-500 dark:text-slate-400 mt-1">Login, eventos del sistema y trazabilidad operativa del sprint 12.</p>
      </div>
      <!-- Tab buttons: horizontal scroll on mobile -->
      <div class="overflow-x-auto">
        <div class="flex min-w-max gap-2">
          <button type="button" (click)="setTab('login')" class="px-4 py-2 text-[10px] font-black uppercase tracking-widest border rounded-none whitespace-nowrap"
            [ngClass]="activeTab === 'login' ? 'bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 border-slate-900 dark:border-slate-100' : 'bg-white dark:bg-slate-900 text-slate-500 dark:text-slate-400 border-slate-200 dark:border-slate-700'">
            Login
          </button>
          <button type="button" (click)="setTab('eventos')" class="px-4 py-2 text-[10px] font-black uppercase tracking-widest border rounded-none whitespace-nowrap"
            [ngClass]="activeTab === 'eventos' ? 'bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 border-slate-900 dark:border-slate-100' : 'bg-white dark:bg-slate-900 text-slate-500 dark:text-slate-400 border-slate-200 dark:border-slate-700'">
            Sistema
          </button>
        </div>
      </div>
    </div>
  </div>

  <!-- Stats Cards: 2-col on mobile, 4-col on md -->
  <div class="grid grid-cols-2 md:grid-cols-4 gap-4">
    <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-4 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
      <p class="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500">Logins exitosos</p>
      <h3 class="text-3xl font-black text-slate-900 dark:text-slate-100 mt-2">{{ totalExitosos }}</h3>
    </div>
    <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-4 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
      <p class="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500">Logins fallidos</p>
      <h3 class="text-3xl font-black text-slate-900 dark:text-slate-100 mt-2">{{ totalFallidos }}</h3>
    </div>
    <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-4 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
      <p class="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500">Usuarios bloqueados</p>
      <h3 class="text-3xl font-black text-slate-900 dark:text-slate-100 mt-2">{{ usuariosBloqueados }}</h3>
    </div>
    <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-4 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
      <p class="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500">Eventos del sistema</p>
      <h3 class="text-3xl font-black text-slate-900 dark:text-slate-100 mt-2">{{ eventosSistema.length }}</h3>
    </div>
  </div>

  <div *ngIf="isLoading" class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-8 text-center transition-colors duration-300">
    <span class="text-xs font-black uppercase tracking-widest text-slate-500 dark:text-slate-400">Cargando auditoría...</span>
  </div>

  <div *ngIf="errorMsg" class="border border-red-200 dark:border-red-900/40 bg-red-50 dark:bg-red-950/30 p-4 text-xs text-red-800 dark:text-red-200 font-semibold">
    {{ errorMsg }}
  </div>

  <div *ngIf="!isLoading && !errorMsg">
    <!-- Summary tables: stack on mobile, side-by-side on xl -->
    <div class="grid grid-cols-1 xl:grid-cols-2 gap-6 mb-6">
      <!-- Last accesses table -->
      <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 overflow-hidden shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
        <div class="p-4 border-b border-slate-100 dark:border-slate-800 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-1">
          <h2 class="text-xs font-black uppercase tracking-widest text-slate-500 dark:text-slate-400">Últimos accesos</h2>
          <span class="text-[10px] font-semibold text-slate-400 dark:text-slate-500">Usuario / IP / Navegador / Fecha / Resultado</span>
        </div>
        <div class="overflow-x-auto">
          <table class="w-full text-left text-xs min-w-max">
            <thead class="bg-slate-50 dark:bg-slate-800/60 text-slate-500 dark:text-slate-400 uppercase tracking-widest font-black">
              <tr>
                <th class="p-3">Usuario</th>
                <th class="p-3">IP</th>
                <th class="p-3">Navegador</th>
                <th class="p-3">Fecha</th>
                <th class="p-3">Resultado</th>
              </tr>
            </thead>
            <tbody>
            <tr *ngFor="let item of ultimosAccesos" class="border-t border-slate-100 dark:border-slate-800">
                <td class="p-3">{{ item.correo || ('Usuario #' + item.usuarioId) }}</td>
                <td class="p-3">{{ item.ip || '-' }}</td>
                <td class="p-3">{{ item.userAgent || '-' }}</td>
                <td class="p-3 whitespace-nowrap">{{ item.fecha | date:'dd/MM/yyyy HH:mm' }}</td>
                <td class="p-3">
                  <span [ngClass]="item.exitoso ? 'text-emerald-700 dark:text-emerald-200 bg-emerald-50 dark:bg-emerald-950/30 border-emerald-200 dark:border-emerald-900/40' : 'text-red-700 dark:text-red-200 bg-red-50 dark:bg-red-950/30 border-red-200 dark:border-red-900/40'"
                    class="px-2 py-1 border text-[10px] font-black uppercase tracking-widest">
                    {{ item.exitoso ? 'Exitoso' : 'Fallido' }}
                  </span>
                </td>
              </tr>
              <tr *ngIf="ultimosAccesos.length === 0">
                <td colspan="5" class="p-6 text-center text-slate-500 dark:text-slate-400">No hay registros de login.</td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>

      <!-- Last events table -->
      <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 overflow-hidden shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
        <div class="p-4 border-b border-slate-100 dark:border-slate-800 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-1">
          <h2 class="text-xs font-black uppercase tracking-widest text-slate-500 dark:text-slate-400">Últimos eventos</h2>
          <span class="text-[10px] font-semibold text-slate-400 dark:text-slate-500">Usuario / Módulo / Acción / Fecha</span>
        </div>
        <div class="overflow-x-auto">
          <table class="w-full text-left text-xs min-w-max">
            <thead class="bg-slate-50 dark:bg-slate-800/60 text-slate-500 dark:text-slate-400 uppercase tracking-widest font-black">
              <tr>
                <th class="p-3">Usuario</th>
                <th class="p-3">Módulo</th>
                <th class="p-3">Acción</th>
                <th class="p-3">Fecha</th>
              </tr>
            </thead>
            <tbody>
            <tr *ngFor="let item of ultimosEventos" class="border-t border-slate-100 dark:border-slate-800">
                <td class="p-3">{{ item.usuarioId || '-' }}</td>
                <td class="p-3 font-bold uppercase">{{ item.modulo }}</td>
                <td class="p-3">{{ item.accion }}</td>
                <td class="p-3 whitespace-nowrap">{{ item.fecha | date:'dd/MM/yyyy HH:mm' }}</td>
              </tr>
              <tr *ngIf="ultimosEventos.length === 0">
                <td colspan="4" class="p-6 text-center text-slate-500 dark:text-slate-400">No hay eventos registrados.</td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>

    <!-- Tab: Login full table -->
    <div *ngIf="activeTab === 'login'" class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 overflow-hidden shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
      <div class="overflow-x-auto">
        <table class="w-full text-left text-xs min-w-max">
          <thead class="bg-slate-50 dark:bg-slate-800/60 text-slate-500 dark:text-slate-400 uppercase tracking-widest font-black">
            <tr>
              <th class="p-3">Fecha</th>
              <th class="p-3">Correo</th>
              <th class="p-3">IP</th>
              <th class="p-3">Estado</th>
              <th class="p-3">Motivo</th>
            </tr>
          </thead>
          <tbody>
            <tr *ngFor="let item of loginAuditoria" class="border-t border-slate-100 dark:border-slate-800">
              <td class="p-3 whitespace-nowrap">{{ item.fecha | date:'dd/MM/yyyy HH:mm' }}</td>
              <td class="p-3">{{ item.correo || ('Usuario #' + item.usuarioId) }}</td>
              <td class="p-3">{{ item.ip || '-' }}</td>
              <td class="p-3">
                <span [ngClass]="item.exitoso ? 'text-emerald-700 bg-emerald-50 border-emerald-200' : 'text-red-700 bg-red-50 border-red-200'"
                  class="px-2 py-1 border text-[10px] font-black uppercase tracking-widest">
                  {{ item.exitoso ? 'Exitoso' : 'Fallido' }}
                </span>
              </td>
              <td class="p-3">{{ item.motivo || '-' }}</td>
            </tr>
            <tr *ngIf="loginAuditoria.length === 0">
              <td colspan="5" class="p-6 text-center text-slate-500 dark:text-slate-400">No hay registros de login.</td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>

    <!-- Tab: Eventos full table -->
    <div *ngIf="activeTab === 'eventos'" class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 overflow-hidden shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
      <div class="overflow-x-auto">
        <table class="w-full text-left text-xs min-w-max">
          <thead class="bg-slate-50 dark:bg-slate-800/60 text-slate-500 dark:text-slate-400 uppercase tracking-widest font-black">
            <tr>
              <th class="p-3">Fecha</th>
              <th class="p-3">Módulo</th>
              <th class="p-3">Acción</th>
              <th class="p-3">Usuario</th>
              <th class="p-3">Descripción</th>
            </tr>
          </thead>
          <tbody>
            <tr *ngFor="let item of eventosSistema" class="border-t border-slate-100 dark:border-slate-800">
              <td class="p-3 whitespace-nowrap">{{ item.fecha | date:'dd/MM/yyyy HH:mm' }}</td>
              <td class="p-3 font-bold uppercase">{{ item.modulo }}</td>
              <td class="p-3">{{ item.accion }}</td>
              <td class="p-3">{{ item.usuarioId || '-' }}</td>
              <td class="p-3">{{ item.descripcion || '-' }}</td>
            </tr>
            <tr *ngIf="eventosSistema.length === 0">
              <td colspan="5" class="p-6 text-center text-slate-500 dark:text-slate-400">No hay eventos registrados.</td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  </div>
</div>
